#!/usr/bin/env node
/**
 * Reads all datasets from dataset/server/dbs/js/ and writes
 * servers/reactnative/src/datasetBundle.ts with all content embedded.
 *
 * Run: node scripts/bundle-datasets.js
 * Also invoked automatically by the npm "postinstall" hook (Jenkins prebuild).
 */

const fs = require('fs');
const path = require('path');

// Paths relative to this script's location (servers/reactnative/scripts/)
const DATASETS_DIR = path.resolve(__dirname, '../../../dataset/server/dbs/js');
const OUT_FILE = path.resolve(__dirname, '../src/datasetBundle.ts');

function readJsonl(filePath) {
  if (!fs.existsSync(filePath)) {
    return [];
  }
  return fs
    .readFileSync(filePath, 'utf8')
    .split('\n')
    .filter(l => l.trim().length > 0)
    .map(l => JSON.parse(l));
}

function main() {
  if (!fs.existsSync(DATASETS_DIR)) {
    console.error(
      `ERROR: datasets directory not found: ${DATASETS_DIR}\n` +
        'Ensure the repo is checked out with dataset/server/dbs/js/ present ' +
        '(Git LFS pull if needed).',
    );
    process.exit(1);
  }

  const datasets = {};

  for (const datasetName of fs.readdirSync(DATASETS_DIR)) {
    const datasetDir = path.join(DATASETS_DIR, datasetName);
    if (!fs.statSync(datasetDir).isDirectory()) {
      continue;
    }

    const indexPath = path.join(datasetDir, 'index.json');
    if (!fs.existsSync(indexPath)) {
      continue;
    }

    const index = JSON.parse(fs.readFileSync(indexPath, 'utf8'));

    const collections = {};
    for (const entry of fs.readdirSync(datasetDir)) {
      if (!entry.endsWith('.jsonl')) {
        continue;
      }
      const collId = entry.replace('.jsonl', '');
      collections[collId] = readJsonl(path.join(datasetDir, entry));
    }

    const blobs = {};
    const attachDir = path.join(datasetDir, 'Attachments');
    if (fs.existsSync(attachDir)) {
      for (const blobFile of fs.readdirSync(attachDir)) {
        if (!blobFile.endsWith('.blob')) {
          continue;
        }
        const raw = fs.readFileSync(path.join(attachDir, blobFile));
        blobs[blobFile] = raw.toString('base64');
      }
    }

    datasets[datasetName] = {index, collections, blobs};
  }

  const datasetNames = Object.keys(datasets);
  if (datasetNames.length === 0) {
    console.error(
      `ERROR: no datasets found under ${DATASETS_DIR}\n` +
        'Expected subdirectories with index.json (names, posts, todo, travel, …).',
    );
    process.exit(1);
  }

  const ts = `// AUTO-GENERATED by scripts/bundle-datasets.js — do not edit by hand.
// Re-run \`npm run bundle-datasets\` after changing files under dataset/server/dbs/js/

export interface DatasetBundle {
  index: {name: string; collections: string[]};
  /** collectionId (e.g. "travel.hotels") → array of raw document objects */
  collections: Record<string, Record<string, unknown>[]>;
  /** filename (e.g. "3ppFYLm0...=.blob") → base64 string */
  blobs: Record<string, string>;
}

const DATASETS: Record<string, DatasetBundle> = ${JSON.stringify(datasets, null, 2)};

export default DATASETS;
`;

  fs.mkdirSync(path.dirname(OUT_FILE), {recursive: true});
  fs.writeFileSync(OUT_FILE, ts, 'utf8');

  const sizeMb = (fs.statSync(OUT_FILE).size / 1024 / 1024).toFixed(1);
  console.log(
    `Wrote ${OUT_FILE} (${sizeMb} MB) — datasets: ${datasetNames.join(', ')}`,
  );
}

main();
